 #if defined(_KERNEL) || defined(__Userspace__)

 uint32_t sctp_calculate_cksum(struct mbuf *, uint32_t);
-void sctp_delayed_cksum(struct mbuf *);
+void sctp_delayed_cksum(struct mbuf *, uint32_t offset);

 #endif				/* _KERNEL */


